select day_Millis AS dayMillis, a.super_agent_account AS superAgentAccount, SUM(a.total_deposit) AS totalDeposit, SUM(a.bet_amount) AS betAmount, SUM(a.number_deposit) AS numberDeposit, SUM(a.advanced_transfer) AS advancedTransfer, SUM(a.number_transfer) AS numberTransfer, SUM(a.central_wallet) AS centralWallet, SUM(a.number_reversals) AS numberReversals, SUM(a.total_withdrawal) AS totalWithdrawal, SUM(a.number_withdrawal) AS numberWithdrawal, SUM(a.number_large_deposits) AS numberLargeDeposits, SUM(a.poor_access) AS poorAccess, SUM(a.member_labour_amount) AS memberLabourAmount, SUM(a.member_vip_labour_amount) AS memberVipLabourAmount, SUM(a.rebate_amount) AS rebateAmount, SUM(a.other_adjustments) AS otherAdjustments, SUM(a.place_order_quantity) AS placeOrderQuantity, SUM(a.active_bet) AS activeBet, SUM(a.betting_profit_loss) AS bettingProfitLoss, SUM(a.trans_agent_time) AS transAgentTime, SUM(a.activity_amount) AS activityAmount, SUM(a.vip_amount) AS vipAmount, SUM(a.already_use_amount) AS alreadyUseAmount FROM report_user_info_statement a
